using System.ComponentModel.DataAnnotations;using System.ComponentModel.DataAnnotations.Schema;namespace CollegeManagementSystem.Data.Entities;[Table("Students")]public class Student{    [Key] public int Id { get; set; }    [Required] [MaxLength(50)] public string FirstName { get; set; } = string.Empty;    [Required] [MaxLength(50)] public string LastName { get; set; } = string.Empty;    [Required] public DateTime DateOfBirth { get; set; }    [Required] public int Phone { get; set; }    [EmailAddress] [MaxLength(255)] public string Email { get; set; } = string.Empty;    public List<Enrollment> Enrollments { get; set; } = [];}